<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Physics Playground</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #1a1a2e;
    color: #e0e0e0;
    font-family: 'Segoe UI', system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    overflow: hidden;
  }
  h1 {
    font-size: 1.4rem;
    margin-bottom: 12px;
    color: #a8d8ea;
    letter-spacing: 1px;
  }
  #sim {
    border: 2px solid #333;
    border-radius: 8px;
    background: #0f0f23;
    cursor: crosshair;
    display: block;
    width: 600px;
    height: 450px;
    max-width: 95vw;
    max-height: 70vh;
  }
  .controls {
    margin-top: 14px;
    display: flex;
    gap: 12px;
  }
  button {
    padding: 10px 28px;
    font-size: 1rem;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    font-weight: 600;
    transition: background 0.15s, transform 0.1s;
  }
  button:active { transform: scale(0.95); }
  #drop { background: #e94560; color: #fff; }
  #drop:hover { background: #ff6b81; }
  #play { background: #0f3460; color: #a8d8ea; border: 1px solid #a8d8ea; }
  #play:hover { background: #16213e; }
  #clear { background: #533483; color: #fff; }
  #clear:hover { background: #6c4fa0; }
</style>
</head>
<body>

<h1>⚽ Bouncing Ball Playground</h1>
<canvas id="sim" width="600" height="450"></canvas>
<div class="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear All</button>
</div>

<script>
(function () {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const dropBtn = document.getElementById('drop');
  const playBtn = document.getElementById('play');
  const clearBtn = document.getElementById('clear');

  // Physics constants
  const GRAVITY = 600;          // pixels/s²
  const RESTITUTION = 0.82;     // energy kept on bounce (0–1)
  const FRICTION = 0.999;       // tiny air resistance per step
  const BALL_COLORS = [
    '#e94560','#f5a623','#50e3c2','#4fc3f7',
    '#ab47bc','#ff7043','#aed581','#ffd54f'
  ];

  let balls = [];
  let running = true;
  let animId = null;
  let lastTime = performance.now();

  // ── helpers ──────────────────────────────────────────────
  function randomColor() {
    return BALL_COLORS[Math.floor(Math.random() * BALL_COLORS.length)];
  }

  function addBall(x, y, vx, vy, r) {
    if (vx === undefined) vx = 0;
    if (vy === undefined) vy = 0;
    if (r === undefined) r = 18 + Math.random() * 22;
    balls.push({ x, y, vx, vy, r, color: randomColor() });
  }

  function clearBalls() {
    balls = [];
  }

  // ── physics step ────────────────────────────────────────
  function step(dt) {
    if (dt <= 0) return;
    const w = canvas.width;
    const h = canvas.height;

    for (let i = 0; i < balls.length; i++) {
      const b = balls[i];

      // gravity
      b.vy += GRAVITY * dt;

      // integrate position
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // air friction
      b.vx *= FRICTION;
      b.vy *= FRICTION;

      // ── wall collisions (clamp + reflect) ─────────────
      // floor
      if (b.y + b.r > h) {
        b.y = h - b.r;
        b.vy = -Math.abs(b.vy) * RESTITUTION;
        // stop micro-bouncing when near rest
        if (Math.abs(b.vy) < 8) b.vy = 0;
      }
      // ceiling
      if (b.y - b.r < 0) {
        b.y = b.r;
        b.vy = Math.abs(b.vy) * RESTITUTION;
      }
      // right wall
      if (b.x + b.r > w) {
        b.x = w - b.r;
        b.vx = -Math.abs(b.vx) * RESTITUTION;
      }
      // left wall
      if (b.x - b.r < 0) {
        b.x = b.r;
        b.vx = Math.abs(b.vx) * RESTITUTION;
      }
    }
  }

  // ── rendering ───────────────────────────────────────────
  function draw() {
    const w = canvas.width;
    const h = canvas.height;

    // clear with dark background
    ctx.fillStyle = '#0f0f23';
    ctx.fillRect(0, 0, w, h);

    // subtle grid
    ctx.strokeStyle = 'rgba(255,255,255,0.04)';
    ctx.lineWidth = 1;
    for (let x = 0; x < w; x += 30) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, h); ctx.stroke();
    }
    for (let y = 0; y < h; y += 30) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(w, y); ctx.stroke();
    }

    // draw balls with glow
    for (const b of balls) {
      // outer glow
      const grad = ctx.createRadialGradient(b.x, b.y, b.r * 0.2, b.x, b.y, b.r * 1.6);
      grad.addColorStop(0, b.color);
      grad.addColorStop(1, 'transparent');
      ctx.fillStyle = grad;
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r * 1.6, 0, Math.PI * 2);
      ctx.fill();

      // ball body
      const bodyGrad = ctx.createRadialGradient(
        b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1,
        b.x, b.y, b.r
      );
      bodyGrad.addColorStop(0, '#fff');
      bodyGrad.addColorStop(0.3, b.color);
      bodyGrad.addColorStop(1, shadeColor(b.color, -40));
      ctx.fillStyle = bodyGrad;
      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fill();

      // highlight
      ctx.fillStyle = 'rgba(255,255,255,0.35)';
      ctx.beginPath();
      ctx.arc(b.x - b.r * 0.25, b.y - b.r * 0.25, b.r * 0.35, 0, Math.PI * 2);
      ctx.fill();
    }
  }

  function shadeColor(hex, percent) {
    const num = parseInt(hex.slice(1), 16);
    let r = (num >> 16) + percent;
    let g = ((num >> 8) & 0xff) + percent;
    let b = (num & 0xff) + percent;
    r = Math.max(0, Math.min(255, r));
    g = Math.max(0, Math.min(255, g));
    b = Math.max(0, Math.min(255, b));
    return '#' + (r << 16 | g << 8 | b).toString(16).padStart(6, '0');
  }

  // ── animation loop ──────────────────────────────────────
  function loop(now) {
    if (!running) { animId = requestAnimationFrame(loop); return; }
    let dt = (now - lastTime) / 1000;
    lastTime = now;
    // clamp to avoid huge jumps
    if (dt > 0.05) dt = 0.05;

    step(dt);
    draw();
    animId = requestAnimationFrame(loop);
  }

  function startLoop() {
    lastTime = performance.now();
    running = true;
    playBtn.textContent = 'Pause';
    if (!animId) animId = requestAnimationFrame(loop);
  }

  // ── event wiring ────────────────────────────────────────
  dropBtn.addEventListener('click', () => {
    const x = 80 + Math.random() * (canvas.width - 160);
    addBall(x, 40, (Math.random() - 0.5) * 120, 0);
  });

  playBtn.addEventListener('click', () => {
    if (running) {
      running = false;
      playBtn.textContent = 'Play';
    } else {
      startLoop();
    }
  });

  clearBtn.addEventListener('click', () => {
    clearBalls();
    draw();
  });

  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    addBall(x, y);
  });

  // ── public API ──────────────────────────────────────────
  window.sim = {
    get w() { return canvas.width; },
    get h() { return canvas.height; },
    balls() {
      return balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
    },
    addBall(x, y, vx, vy, r) {
      addBall(x, y, vx, vy, r);
    },
    clear() {
      clearBalls();
    },
    step(dt) {
      if (dt === undefined) dt = 1;
      // dt here is in "steps" — treat as seconds for physics
      step(dt);
      draw();
    }
  };

  // ── initial draw & start ────────────────────────────────
  draw();
  animId = requestAnimationFrame(loop);
})();
</script>
</body>
</html>
